# -*- coding: utf-8 -*-
"""Jismoniy tarbiya - 15 mavzu konspekt generatori."""
import zipfile, datetime
TOPICS = []
def esc(t): return t.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
def run(text,bold=False,size=28,font="Times New Roman"):
    rpr='<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>'%(font,font,font)
    if bold: rpr+='<w:b/><w:bCs/>'
    rpr+='<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>'%(size,size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>'%(rpr,esc(text))
def para(text,bold=False,size=28,align="both",indent_first=709,space_after=120,line=360,keep_next=False):
    ppr='<w:pPr>'
    if keep_next: ppr+='<w:keepNext/>'
    ppr+='<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>'%(space_after,line)
    if indent_first: ppr+='<w:ind w:firstLine="%d"/>'%indent_first
    ppr+='<w:jc w:val="%s"/></w:pPr>'%align
    return '<w:p>%s%s</w:p>'%(ppr,run(text,bold=bold,size=size))
def page_break(): return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'
def empty_para(): return '<w:p><w:pPr><w:spacing w:after="0" w:line="360" w:lineRule="auto"/></w:pPr></w:p>'
def build_topic(t,is_first):
    parts=[]
    if not is_first: parts.append(page_break())
    parts.append(para("%d-MAVZU. %s"%(t["num"],t["title"].upper()),bold=True,size=30,align="center",indent_first=0,space_after=180,keep_next=True))
    parts.append(para("Reja:",bold=True,size=28,align="left",indent_first=0,space_after=60,keep_next=True))
    for i,r in enumerate(t["reja"],1): parts.append(para("%d. %s"%(i,r),size=28,align="left",indent_first=360,space_after=40))
    parts.append(empty_para())
    for idx,(head,paras) in enumerate(t["sections"],1):
        parts.append(para("%d. %s"%(idx,head),bold=True,size=28,align="left",indent_first=0,space_after=80,keep_next=True))
        for p in paras: parts.append(para(p,size=28,align="both",indent_first=709,space_after=120))
    return "".join(parts)
def build_document():
    body="".join(build_topic(t,i==0) for i,t in enumerate(TOPICS))
    sect='<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>'+body+sect+'</w:body></w:document>'
CT='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'
def cp():
    n=datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Jismoniy tarbiya</dc:title><dc:creator>Konspekt</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>'%(n,n)
AP='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Konspekt</Application></Properties>'
def write_docx(path):
    with zipfile.ZipFile(path,"w",zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml",CT); z.writestr("_rels/.rels",RE)
        z.writestr("word/document.xml",build_document()); z.writestr("word/_rels/document.xml.rels",DR)
        z.writestr("word/styles.xml",ST); z.writestr("docProps/core.xml",cp()); z.writestr("docProps/app.xml",AP)
    print("OK:",path,"|",len(TOPICS),"mavzu")

TOPICS.append({"num":1,"title":"Tanlangan sport turining tavsifnomasi, tarixi va O'zbekistonga kirib kelishi","reja":["Sport turi tushunchasi va uning tasnifi.","Tanlangan sport turining umumiy tavsifi.","Sport turining kelib chiqish tarixi.","Sport turining O'zbekistonga kirib kelishi va rivojlanishi."],"sections":[("Sport turi tushunchasi va uning tasnifi",["Sport turi — bu muayyan qoidalar asosida olib boriladigan, jismoniy va aqliy qobiliyatlarni namoyon etishga qaratilgan musobaqa faoliyatidir. Har bir sport turi o'ziga xos texnika, taktika, qoidalar va jihozlarga ega. Jahonda 200 dan ortiq rasmiy sport turlari mavjud.","Sport turlari turli mezonlarga ko'ra tasniflanadi: jismoniy harakat xususiyatiga ko'ra (yengil atletika, og'ir atletika), jamoaviy yoki yakka (futbol, kurash), mavsumiy (yozgi, qishki), o'yin va o'yinsiz turlar. Bu tasnif sportni o'rganishni osonlashtiradi.","Olimpiya sport turlari alohida ahamiyatga ega: ular Xalqaro olimpiya qo'mitasi (XOK) tomonidan tan olingan va Olimpiya o'yinlari dasturiga kiritilgan. O'zbekiston sportchilari ko'plab sport turlarida xalqaro miqyosda yuqori natijalarga erishmoqda."]),("Tanlangan sport turining umumiy tavsifi",["Har bir sport turining o'ziga xos tavsifnomasi bor: u qanday harakatlardan iborat, qanday jismoniy sifatlarni talab qiladi (kuch, tezlik, chidamlilik, epchillik, egiluvchanlik), nechta ishtirokchi qatnashadi va qanday natijaga erishish maqsad qilinadi.","Sport turining tavsifi uning mohiyatini ochib beradi: musobaqa shakli (yakka tartibda yoki jamoa bilan), g'olibni aniqlash usuli (vaqt, masofa, ochko, gol), kerakli jihozlar va maydon talablari. Bu xususiyatlar sportchining tayyorgarlik dasturini belgilaydi.","Sport turining ijtimoiy ahamiyati ham muhim: u sog'lom turmush tarzini targ'ib qiladi, yoshlarni jismoniy tarbiyalaydi, milliy g'urur tuyg'usini shakllantiradi va xalqlar o'rtasida do'stlikni mustahkamlaydi. Sport — insoniyatning umumiy tili hisoblanadi."]),("Sport turining kelib chiqish tarixi",["Aksariyat sport turlari uzoq tarixga ega. Ularning ildizlari qadimgi davrlarga — Misr, Yunoniston, Rim, Xitoy va boshqa qadimgi sivilizatsiyalarga borib taqaladi. Qadimgi Yunonistonda Olimpiya o'yinlari eramizdan avvalgi 776-yilda boshlangan.","Ko'p zamonaviy sport turlari XIX asrda Yevropada, ayniqsa Angliyada shakllangan va rasmiy qoidalarga ega bo'lgan. Bu davrda sport klublari, federatsiyalar tashkil etilib, musobaqa qoidalari yagona shaklga keltirilgan. 1896-yilda zamonaviy Olimpiya o'yinlari qayta tiklangan.","Sport turlarining rivojlanishi jamiyat taraqqiyoti bilan bog'liq: texnologiya rivoji yangi jihozlar yaratdi, ommaviy axborot vositalari sportni keng targ'ib qildi, xalqaro musobaqalar tashkil etildi. Bugungi kunda sport — global hodisa va katta industriyadir."]),("Sport turining O'zbekistonga kirib kelishi va rivojlanishi",["O'zbekiston hududida jismoniy mashqlar va sport o'yinlari qadimdan mavjud bo'lgan: kurash, ot o'yinlari (ko'pkari), kamondan otish, qilichbozlik milliy sport turlari sifatida rivojlangan. Bu turlar xalq an'analari va bayramlari bilan chambarchas bog'liq edi.","Zamonaviy sport turlari O'zbekistonga asosan XX asr boshida kirib keldi. Sovet davrida sport ommaviy tus oldi, sport maktablari, stadionlar va sport jamiyatlari tashkil etildi. Ko'plab sportchilarimiz ittifoq va xalqaro miqyosda yuqori natijalarga erishdi.","Mustaqillik yillarida sport sohasiga davlat e'tibori sezilarli kuchaydi: zamonaviy sport inshootlari qurildi, sport maktablari tarmog'i kengaytirildi, sportchilarni qo'llab-quvvatlash tizimi yaratildi. O'zbekiston sportchilari Olimpiya o'yinlari va jahon chempionatlarida muvaffaqiyatli ishtirok etib, mamlakat sharafini himoya qilmoqda."])],})

TOPICS.append({"num":2,"title":"Tanlangan sport turining maydon o'rnatish va musobaqa qoidalari","reja":["Sport maydoni va uning o'lchamlari.","Maydonni o'rnatish va jihozlash talablari.","Musobaqa qoidalari va ularning mohiyati.","Hakamlik va musobaqani baholash tartibi."],"sections":[("Sport maydoni va uning o'lchamlari",["Har bir sport turi o'ziga xos maydon yoki sport inshootida o'tkaziladi. Maydon o'lchamlari xalqaro federatsiyalar tomonidan qat'iy belgilangan va barcha rasmiy musobaqalarda bir xil bo'lishi shart. Bu adolatli musobaqani ta'minlaydi.","Maydon turlari sport turiga bog'liq: ochiq maydonlar (futbol, yengil atletika), yopiq zallar (gimnastika, basketbol), suv havzalari (suzish), maxsus traslar (velosport), gilamlar (kurash, gimnastika). Har birining o'z standartlari mavjud.","Maydon belgilashda chiziqlar, zonalar va belgilar muhim ahamiyatga ega: ular o'yin maydonini chegaralaydi, maxsus zonalarni ko'rsatadi va qoidalarning bajarilishini ta'minlaydi. Chiziqlar aniq, ko'rinadigan va belgilangan kenglikda bo'lishi kerak."]),("Maydonni o'rnatish va jihozlash talablari",["Maydonni o'rnatish jarayoni qat'iy talablar asosida amalga oshiriladi: yer yuzasi tekis va xavfsiz bo'lishi, kerakli o'lchamlar aniq belgilangan bo'lishi, jihozlar mustahkam o'rnatilgan bo'lishi va yoritish yetarli bo'lishi kerak.","Maydon jihozlari: darvozalar, to'rlar, savatlar, to'siqlar, belgilar — bularning hammasi standartga mos bo'lishi va mustahkam o'rnatilishi shart. Jihozlarning xavfsizligi ayniqsa muhim — ular sportchilarga shikast yetkazmasligi kerak.","Maydonning qo'shimcha qismlari: tomoshabinlar uchun joylar, sportchilar va hakamlar uchun zonalar, kiyim almashtirish xonalari, tibbiy yordam punkti. Yirik musobaqalarda axborot tablolar, video takrorlash tizimlari va boshqa zamonaviy texnologiyalar ham qo'llaniladi."]),("Musobaqa qoidalari va ularning mohiyati",["Musobaqa qoidalari — sport turida o'yinni tartibga soluvchi rasmiy normalardir. Ular musobaqaning adolatli, xavfsiz va tartibli o'tishini ta'minlaydi. Qoidalar xalqaro federatsiyalar tomonidan ishlab chiqiladi va vaqti-vaqti bilan yangilanadi.","Qoidalar quyidagi masalalarni qamrab oladi: o'yin davomiyligi, ishtirokchilar soni, ruxsat etilgan va taqiqlangan harakatlar, ochko hisoblash tartibi, qoidabuzarlik va jazolar tizimi. Har bir sportchi va murabbiy qoidalarni mukammal bilishi kerak.","Qoidalarni bilish va ularga rioya qilish — sportchining asosiy majburiyati. Qoidabuzarlik turli jazolarga olib keladi: ogohlantirish, jarima, ochko yo'qotish yoki musobaqadan chetlatish. Halol o'yin (fair play) tamoyili sportning asosiy qadriyatidir."]),("Hakamlik va musobaqani baholash tartibi",["Hakam — musobaqada qoidalarning bajarilishini nazorat qiluvchi va natijani baholovchi rasmiy shaxs. Hakamlar maxsus tayyorgarlikdan o'tadi, qoidalarni mukammal biladi va xolis bo'lishi shart. Yirik musobaqalarda bir nechta hakam ishlaydi.","Baholash tizimi sport turiga bog'liq: ba'zi turlarda natija obyektiv o'lchanadi (vaqt, masofa, og'irlik), boshqalarida hakamlar baho beradi (gimnastika, figurali uchish). Subyektiv baholashda bir nechta hakam ishtirok etadi va o'rtacha ball hisoblanadi.","Zamonaviy texnologiyalar hakamlik aniqligini oshiradi: video takrorlash (VAR futbolda), elektron o'lchash tizimlari, fotofinish, sensorlar. Bu texnologiyalar adolatli va aniq baholashni ta'minlab, bahsli vaziyatlarni hal qilishga yordam beradi."])],})

TOPICS.append({"num":3,"title":"Tanlangan sport turiga oid sport formasi va undagi gigiyenik talablar","reja":["Sport formasi tushunchasi va uning vazifalari.","Sport formasiga qo'yiladigan talablar.","Sport formasidagi gigiyenik talablar.","Sport poyabzali va himoya vositalari."],"sections":[("Sport formasi tushunchasi va uning vazifalari",["Sport formasi — sportchining mashg'ulot va musobaqalarda kiyadigan maxsus kiyimidir. U sport turiga moslashtirilgan bo'lib, sportchining erkin harakatlanishini, qulayligini va xavfsizligini ta'minlaydi. To'g'ri tanlangan forma sport natijasiga ta'sir qiladi.","Sport formasining asosiy vazifalari: harakat erkinligini ta'minlash, tananing harorat balansini saqlash, terni so'rib olish va bug'lantirish, shikastlanishdan himoya qilish va jamoa mansubligini ko'rsatish (jamoa formasi, raqamlar, ranglar).","Har bir sport turining o'ziga xos formasi bor: suzuvchilar uchun maxsus kostyum, yengil atletikachilar uchun yengil kiyim, kurashchilar uchun kurtka, futbolchilar uchun futbolka va shortilar. Forma sport turining xususiyatlariga to'liq mos bo'lishi kerak."]),("Sport formasiga qo'yiladigan talablar",["Sport formasiga qo'yiladigan asosiy talablar: qulaylik (harakatga xalaqit bermaslik), mustahkamlik (uzoq xizmat qilish), yengillik (ortiqcha og'irlik bo'lmasligi), nafas oluvchanlik (havo o'tkazishi) va estetik ko'rinish (chiroyli va toza).","Forma materiali muhim ahamiyatga ega: zamonaviy sport kiyimlari maxsus sintetik tolalardan tayyorlanadi. Ular terni tez so'rib oladi, tashqariga chiqaradi va teri quruq qoladi. Bu sportchining qulayligini va samaradorligini oshiradi.","Forma o'lchami aniq tanlanishi kerak: juda tor forma harakatga xalaqit beradi va qon aylanishini buzadi, juda keng forma esa noqulay va harakatga to'sqinlik qiladi. Forma sportchining tana o'lchamiga mos kelishi shart."]),("Sport formasidagi gigiyenik talablar",["Gigiyenik talablar — sport formasining sog'liq uchun xavfsiz va foydali bo'lishini ta'minlovchi qoidalardir. Forma toza saqlanishi, muntazam yuvilishi va quritilishi kerak. Iflos forma terining kasalliklariga va infeksiyalarga sabab bo'ladi.","Material gigiyenasi: forma matosi teri uchun zararsiz, allergiya keltirmaydigan va havo hamda namlikni o'tkazadigan bo'lishi kerak. Tabiiy tolalar (paxta) yoki sifatli sintetik materiallar afzal. Sun'iy, havo o'tkazmaydigan materiallar teri kasalliklariga olib keladi.","Shaxsiy gigiyena qoidalari: har bir sportchi o'z shaxsiy formasiga ega bo'lishi, mashg'ulotdan keyin formani yuvishi, terlagan formani quritishi va boshqalar bilan forma almashmasligi kerak. Bu gigiyenik qoidalar sog'liqni saqlash uchun zarurdir."]),("Sport poyabzali va himoya vositalari",["Sport poyabzali — sport formasining muhim qismi. Har bir sport turi uchun maxsus poyabzal mavjud: yugurish uchun krossovkalar, futbol uchun butsalar, kurash uchun maxsus tuflilar. Poyabzal oyoqni himoya qiladi va harakat samaradorligini oshiradi.","Poyabzalga qo'yiladigan talablar: oyoq o'lchamiga aniq mos kelishi, qulay va yengil bo'lishi, oyoqni mustahkam ushlab turishi, zarbani yumshatishi va sirpanmasligi. Noto'g'ri poyabzal oyoq shikastlanishiga va boshqa muammolarga olib keladi.","Himoya vositalari ko'p sport turlarida zarur: dubulg'a (velosport, beysbol), tizza va tirsak himoyachilari, qo'lqoplar, og'iz himoyachisi (boks), maxsus nimchalar. Bu vositalar sportchini jiddiy shikastlanishlardan himoya qiladi va xavfsizlikni ta'minlaydi."])],})

TOPICS.append({"num":4,"title":"Tanlangan sport turiga oid jihozlar va texnika qoidalari","reja":["Sport jihozlari tushunchasi va turlari.","Jihozlarga qo'yiladigan standart talablar.","Jihozlardan foydalanish texnika qoidalari.","Jihozlarni saqlash va texnik xizmat ko'rsatish."],"sections":[("Sport jihozlari tushunchasi va turlari",["Sport jihozlari — sport turida foydalaniladigan maxsus uskunalar va vositalardir. Ular sportchiga mashq qilish va musobaqalarda qatnashish imkonini beradi. Jihozlar sport turiga qarab turlicha bo'ladi va aniq standartlarga mos kelishi kerak.","Jihozlar turlariga ko'ra bo'linadi: individual jihozlar (sportchi shaxsan foydalanadigan — raketka, to'p, nayza), umumiy jihozlar (maydon jihozlari — darvoza, to'r, savat) va yordamchi jihozlar (mashq uchun — gantellar, to'siqlar, trenajyorlar).","Zamonaviy sport jihozlari yuqori texnologiyalar asosida ishlab chiqariladi: yengil va mustahkam materiallar, aerodinamik shakllar, aniq o'lchamlar. Jihozlar sifati sport natijalariga sezilarli ta'sir qiladi, shuning uchun ularni to'g'ri tanlash muhim."]),("Jihozlarga qo'yiladigan standart talablar",["Sport jihozlari xalqaro federatsiyalar tomonidan belgilangan standartlarga mos kelishi shart. Bu standartlar jihozlarning o'lchamlari, og'irligi, materiallari va xususiyatlarini aniq belgilaydi. Standartga mos kelmaydigan jihozlar musobaqalarda ishlatilmaydi.","Standartlashtirish adolatli musobaqani ta'minlaydi: barcha sportchilar bir xil sharoitda, bir xil jihozlar bilan musobaqalashadi. Masalan, futbol to'pining og'irligi, o'lchami va bosimi qat'iy belgilangan; yengil atletikada nayza, disk va yadro og'irligi standartlashtirilgan.","Jihozlar sertifikatlashtirish jarayonidan o'tadi: ular sinovdan o'tkazilib, standartga mosligi tasdiqlanadi va maxsus belgi (sertifikat) bilan ta'minlanadi. Rasmiy musobaqalarda faqat sertifikatlangan jihozlardan foydalanish mumkin."]),("Jihozlardan foydalanish texnika qoidalari",["Har bir jihozdan to'g'ri foydalanish texnikasi mavjud. Sportchi jihozni to'g'ri ushlash, harakatga keltirish va boshqarishni o'rganishi kerak. Noto'g'ri texnika nafaqat natijani pasaytiradi, balki shikastlanishga ham olib kelishi mumkin.","Texnik qoidalar jihozning xususiyatlariga bog'liq: raketka bilan to'pni urish texnikasi, nayza otish texnikasi, og'ir atletikada shtangani ko'tarish texnikasi. Bu texnikalar murabbiy rahbarligida bosqichma-bosqich o'rganiladi va mashq qilinadi.","Jihozdan foydalanishda xavfsizlik qoidalariga rioya qilish muhim: jihozni faqat belgilangan maqsadda ishlatish, atrofdagilarga zarar yetkazmaslik, nosoz jihozdan foydalanmaslik. Xavfsizlik qoidalari shikastlanishlarning oldini oladi."]),("Jihozlarni saqlash va texnik xizmat ko'rsatish",["Sport jihozlarini to'g'ri saqlash ularning uzoq xizmat qilishini ta'minlaydi. Jihozlar quruq, toza va maxsus joyda saqlanishi kerak. Namlik, issiqlik va to'g'ridan-to'g'ri quyosh nuri ko'p jihozlarga zarar yetkazadi.","Texnik xizmat ko'rsatish muntazam amalga oshirilishi kerak: jihozlarni tekshirish, tozalash, ta'mirlash va kerak bo'lganda almashtirish. Nosoz jihoz xavfli — u shikastlanishga sabab bo'lishi mumkin, shuning uchun har gal foydalanishdan oldin jihoz holati tekshiriladi.","Jihozlarni hisobga olish va tartibga solish ham muhim: har bir jihozning holati qayd etiladi, foydalanish muddati nazorat qilinadi va yangilash rejasi tuziladi. To'g'ri boshqarish sport tashkilotining samarali ishlashini ta'minlaydi."])],})

TOPICS.append({"num":5,"title":"Tanlangan sport turiga oid sport formasi va undagi gigiyenik talablar","reja":["Sport formasi va inson sog'lig'i munosabati.","Turli iqlim sharoitlari uchun sport formasi.","Formaning materiallari va ularning xususiyatlari.","Sport gigiyenasining umumiy qoidalari."],"sections":[("Sport formasi va inson sog'lig'i munosabati",["Sport formasi sportchining sog'lig'iga bevosita ta'sir qiladi. To'g'ri tanlangan, sifatli forma tananing optimal harorat rejimini saqlaydi, terni tashqariga chiqaradi va teri nafas olishini ta'minlaydi. Bu sportchining sog'lig'i va samaradorligi uchun muhim.","Noto'g'ri yoki sifatsiz forma turli muammolarga olib kelishi mumkin: teri qichishishi va allergiya, terlash buzilishi, organizmning haddan tashqari qizishi yoki sovushi, qon aylanishining buzilishi. Shuning uchun forma tanlashda sog'liq omillari hisobga olinishi shart.","Sport formasi gigiyenasi inson salomatligini muhofaza qilishning muhim qismidir. Toza, quruq va mos forma kasalliklarning oldini oladi, sportchining qulayligini ta'minlaydi va mashg'ulot samaradorligini oshiradi. Gigiyenaga e'tiborsizlik jiddiy oqibatlarga olib keladi."]),("Turli iqlim sharoitlari uchun sport formasi",["Sport formasi iqlim va ob-havo sharoitlariga mos tanlanishi kerak. Issiq havoda yengil, ochiq rangli, havo o'tkazadigan forma kiyiladi — bu tananing qizib ketishining oldini oladi. Sovuq havoda esa issiqlikni saqlovchi qatlamli kiyim zarur.","Qishki sport turlari (chang'i, konkida uchish) uchun maxsus issiqlik saqlovchi, shamol va namlikdan himoya qiluvchi forma kerak. Yozgi sport turlarida esa terni tez so'ruvchi, quyoshdan himoya qiluvchi yengil kiyim afzal ko'riladi.","Qatlamli kiyinish tamoyili sovuq sharoitlarda muhim: birinchi qatlam terni so'radi, ikkinchi qatlam issiqlikni saqlaydi, uchinchi qatlam shamol va namlikdan himoya qiladi. Bu tizim organizmning issiqlik balansini optimal saqlaydi."]),("Formaning materiallari va ularning xususiyatlari",["Sport formasi turli materiallardan tayyorlanadi: tabiiy (paxta, jun) va sintetik (poliester, naylon, laykra, spandeks). Har bir materialning o'z afzalliklari va kamchiliklari bor. Zamonaviy formalar ko'pincha aralash materiallardan tayyorlanadi.","Paxta tabiiy, teri uchun yumshoq va nafas oluvchan, lekin terni so'rganda og'irlashadi va sekin quriydi. Sintetik materiallar terni tez chiqaradi, yengil va tez quriydi, lekin ba'zilari havo o'tkazmaydi. Eng yaxshi natija aralash materiallarda.","Zamonaviy texnologik materiallar: nam boshqaruvchi (moisture-wicking) matolar terni teridan tashqariga chiqaradi, antibakterial qoplamalar hidning oldini oladi, kompressiya matolari mushaklarni qo'llab-quvvatlaydi. Bu materiallar sport natijalarini yaxshilaydi."]),("Sport gigiyenasining umumiy qoidalari",["Sport gigiyenasi — sportchining sog'lig'ini muhofaza qilishga qaratilgan qoidalar majmuasidir. Ular shaxsiy gigiyena (tana tozaligi, forma tozaligi), mashg'ulot gigiyenasi (rejim, yuklama) va atrof-muhit gigiyenasini (toza havo, maydon tozaligi) o'z ichiga oladi.","Shaxsiy gigiyena qoidalari: muntazam yuvinish (mashg'ulotdan keyin dush qabul qilish), toza forma kiyish, shaxsiy buyumlardan (sochiq, poyabzal) foydalanish, tirnoq va sochlarni tartibli saqlash. Bu qoidalar teri kasalliklari va infeksiyalarning oldini oladi.","Umumiy sog'lomlashtirish qoidalari: to'g'ri ovqatlanish, yetarli uyqu, kun tartibiga rioya qilish, chiniqish va yomon odatlardan (chekish, ichkilik) voz kechish. Sport gigiyenasiga rioya qilish sportchining yuqori natijalarga erishishi va sog'lig'ini saqlashi uchun zarur shartdir."])],})

TOPICS.append({"num":6,"title":"Tanlangan sport turiga oid sportchi tayyorlash","reja":["Sportchini tayyorlash tushunchasi va tizimi.","Tayyorgarlikning asosiy turlari.","Tayyorgarlik bosqichlari va davrlari.","Sportchi tayyorlashda murabbiyning roli."],"sections":[("Sportchini tayyorlash tushunchasi va tizimi",["Sportchini tayyorlash — bu sportchining jismoniy, texnik, taktik, ruhiy va nazariy sifatlarini rivojlantirishga qaratilgan tizimli va uzoq muddatli jarayondir. Uning maqsadi — sportchini yuqori natijalarga erishishga tayyorlashdir.","Sportchi tayyorlash tizimi bir necha tarkibiy qismdan iborat: mashg'ulot jarayoni (asosiy qism), musobaqalarda ishtirok etish, tiklanish va dam olish, tibbiy nazorat va to'g'ri ovqatlanish. Bu qismlar bir-biri bilan uzviy bog'liq.","Tayyorgarlik ilmiy asoslarga tayanadi: sport fiziologiyasi, biomexanika, psixologiya, pedagogika va tibbiyot yutuqlaridan foydalaniladi. Zamonaviy sportda ilmiy yondashuv va texnologiyalar sportchining samaradorligini sezilarli oshiradi."]),("Tayyorgarlikning asosiy turlari",["Sportchi tayyorgarligi besh asosiy turdan iborat: jismoniy tayyorgarlik (kuch, tezlik, chidamlilik), texnik tayyorgarlik (harakat texnikasi), taktik tayyorgarlik (musobaqa strategiyasi), ruhiy (psixologik) tayyorgarlik va nazariy tayyorgarlik (bilimlar).","Har bir tayyorgarlik turi muhim va ular birgalikda sportchining yaxlit mahoratini shakllantiradi. Faqat jismonan kuchli, lekin texnikasi zaif sportchi yuqori natijaga erisha olmaydi. Shuning uchun barcha turlar muvozanatli rivojlantirilishi kerak.","Tayyorgarlik turlarining nisbati sport turiga va sportchining darajasiga bog'liq: boshlang'ich bosqichda umumiy jismoniy tayyorgarlik ustun, yuqori darajada esa maxsus texnik va taktik tayyorgarlikka ko'proq e'tibor qaratiladi."]),("Tayyorgarlik bosqichlari va davrlari",["Sportchi tayyorlash uzoq muddatli jarayon bo'lib, bir necha bosqichdan iborat: boshlang'ich tayyorgarlik (sport bilan tanishish), bazaviy tayyorgarlik (asoslarni o'rganish), maxsuslashtirish (muayyan sport turiga chuqurlashish) va yuqori mahorat bosqichi.","Yillik tayyorgarlik tsikli uch davrga bo'linadi: tayyorgarlik davri (asosiy mashg'ulotlar, jismoniy tayyorgarlik), musobaqa davri (musobaqalarga tayyorlanish va ishtirok etish) va o'tish davri (faol dam olish, tiklanish). Bu davrlar takrorlanib turadi.","Tayyorgarlikni rejalashtirish (periodizatsiya) muhim: yuklama va dam olish to'g'ri taqsimlanishi, asosiy musobaqalarga eng yaxshi shaklda kelish ta'minlanishi kerak. To'g'ri rejalashtirish charchash va shikastlanishning oldini oladi."]),("Sportchi tayyorlashda murabbiyning roli",["Murabbiy — sportchi tayyorlashning markaziy figurasi. U mashg'ulot jarayonini rejalashtiradi, sportchining texnikasini shakllantiradi, taktikani o'rgatadi, ruhiy qo'llab-quvvatlaydi va sportchining rivojlanishini nazorat qiladi. Murabbiy mahorati natijaga bevosita ta'sir qiladi.","Murabbiyning vazifalari ko'p qirrali: ustoz (bilim va ko'nikma beradi), psixolog (ruhiy holatni boshqaradi), tashkilotchi (mashg'ulot va musobaqalarni tashkil etadi), tarbiyachi (axloqiy fazilatlarni shakllantiradi) va maslahatchi (hayotiy masalalarda yordam beradi).","Zamonaviy murabbiy keng bilimga ega bo'lishi kerak: sport nazariyasi, fiziologiya, psixologiya, pedagogika, tibbiyot asoslari va zamonaviy texnologiyalar. Murabbiy doimo o'z bilimini oshirib borishi va yangi metodikalarni o'rganishi zarur."])],})

TOPICS.append({"num":7,"title":"Sportchini jismoniy, texnik, taktik tayyorgarligi","reja":["Jismoniy tayyorgarlik va uning tarkibi.","Texnik tayyorgarlik va harakat ko'nikmalari.","Taktik tayyorgarlik asoslari.","Tayyorgarlik turlarining o'zaro bog'liqligi."],"sections":[("Jismoniy tayyorgarlik va uning tarkibi",["Jismoniy tayyorgarlik — sportchining jismoniy sifatlarini (kuch, tezlik, chidamlilik, epchillik, egiluvchanlik) rivojlantirishga qaratilgan tayyorgarlik turidir. U barcha boshqa tayyorgarlik turlarining asosi hisoblanadi va sport natijasining poydevorini tashkil etadi.","Jismoniy tayyorgarlik ikki turga bo'linadi: umumiy jismoniy tayyorgarlik (UJT — barcha jismoniy sifatlarni har tomonlama rivojlantirish) va maxsus jismoniy tayyorgarlik (MJT — muayyan sport turiga kerakli sifatlarni rivojlantirish). Ikkalasi ham zarur.","Asosiy jismoniy sifatlar: kuch (mushaklarning qarshilikni yengish qobiliyati), tezlik (harakatni tez bajarish), chidamlilik (uzoq vaqt ish bajarish), epchillik (murakkab harakatlarni bajarish) va egiluvchanlik (bo'g'imlardagi harakat hajmi). Har biri maxsus mashqlar bilan rivojlantiriladi."]),("Texnik tayyorgarlik va harakat ko'nikmalari",["Texnik tayyorgarlik — sport turiga xos harakatlarni to'g'ri va samarali bajarishni o'rgatishga qaratilgan tayyorgarlik. Sport texnikasi — bu muayyan vazifani eng oqilona va samarali hal qilish usulidir. To'g'ri texnika — yuqori natijaning kaliti.","Texnik tayyorgarlik bosqichma-bosqich amalga oshiriladi: avval harakat bilan tanishish, keyin uni o'rganish (alohida elementlar), so'ngra mustahkamlash (takrorlash orqali) va nihoyat takomillashtirish (avtomatizm darajasiga yetkazish). Bu jarayon ko'p mashq talab qiladi.","Harakat ko'nikmasi — ko'p marta takrorlash natijasida avtomatlashgan harakat. Mukammal egallangan ko'nikma sportchiga ortiqcha o'ylamasdan, tabiiy va aniq harakat qilish imkonini beradi. Bu musobaqada katta afzallik beradi va xatolar ehtimolini kamaytiradi."]),("Taktik tayyorgarlik asoslari",["Taktik tayyorgarlik — musobaqada raqibni yengish uchun oqilona harakat usullarini o'rgatishga qaratilgan tayyorgarlik. Taktika — bu sportchining o'z kuchi va imkoniyatlaridan to'g'ri foydalanib, raqib ustidan g'alaba qozonish san'atidir.","Taktik tayyorgarlik quyidagilarni o'z ichiga oladi: raqibni o'rganish (kuchli va zaif tomonlarini bilish), musobaqa rejasini tuzish, har xil vaziyatlarga moslashish, kuchni to'g'ri taqsimlash va qaror qabul qilish. Taktika individual va jamoaviy bo'lishi mumkin.","Taktik mahorat tajriba va bilim asosida shakllanadi: sportchi ko'p musobaqalarda qatnashib, turli raqiblar bilan o'ynab, taktik fikrlashni rivojlantiradi. Murabbiy taktik tahlil o'tkazadi, video yozuvlarni o'rganadi va sportchiga taktik ko'rsatmalar beradi."]),("Tayyorgarlik turlarining o'zaro bog'liqligi",["Jismoniy, texnik va taktik tayyorgarlik bir-biri bilan chambarchas bog'liq va bir-birini to'ldiradi. Yaxshi jismoniy tayyorgarlik texnikani to'g'ri bajarish imkonini beradi, mukammal texnika esa taktik vazifalarni samarali hal qilishga yordam beradi.","Bu turlarning muvozanatli rivojlanishi muhim: faqat bir turga e'tibor berib, boshqalarini e'tiborsiz qoldirish noto'g'ri. Masalan, kuchli, lekin taktik fikrlay olmaydigan sportchi yoki texnikasi yaxshi, lekin jismonan zaif sportchi yuqori natijaga erisha olmaydi.","Yaxlit tayyorgarlik tizimi sportchining barcha sifatlarini integratsiyalashgan holda rivojlantiradi. Zamonaviy sportda kompleks yondashuv qo'llaniladi — barcha tayyorgarlik turlari yagona maqsadga, ya'ni yuqori sport natijasiga erishishga yo'naltiriladi."])],})

TOPICS.append({"num":8,"title":"Sportchini jismoniy tayyorlashning mazmuni va mashqlari","reja":["Jismoniy tayyorlashning maqsadi va vazifalari.","Kuch va tezlik sifatlarini rivojlantirish.","Chidamlilikni rivojlantirish usullari.","Epchillik va egiluvchanlikni rivojlantirish."],"sections":[("Jismoniy tayyorlashning maqsadi va vazifalari",["Jismoniy tayyorlashning asosiy maqsadi — sportchining jismoniy sifatlarini har tomonlama rivojlantirish va sport turiga xos jismoniy qobiliyatlarni shakllantirishdir. Bu sportchining yuqori natijalarga erishishi uchun zaruriy asos yaratadi.","Jismoniy tayyorlashning vazifalari: organizmning funksional imkoniyatlarini oshirish, asosiy harakat sifatlarini rivojlantirish, sog'liqni mustahkamlash, ish qobiliyatini oshirish va shikastlanishlarning oldini olish. Bu vazifalar tizimli mashg'ulotlar orqali hal qilinadi.","Jismoniy tayyorlash umumiy (UJT) va maxsus (MJT) ga bo'linadi. UJT organizmni har tomonlama rivojlantiradi va barcha sport turlari uchun zarur. MJT esa muayyan sport turining talablariga moslashtirilgan sifatlarni rivojlantiradi."]),("Kuch va tezlik sifatlarini rivojlantirish",["Kuch — mushaklarning tashqi qarshilikni yengish yoki unga qarshilik ko'rsatish qobiliyatidir. Kuchni rivojlantirish mashqlari: og'irlik bilan mashqlar (shtanga, gantellar), o'z tana og'irligi bilan mashqlar (otjimaniya, tortilish), trenajyorlarda mashqlar va qarshilikka qarshi mashqlar.","Tezlik — harakatni eng qisqa vaqtda bajarish qobiliyatidir. Tezlikni rivojlantirish mashqlari: qisqa masofaga yugurish (sprint), tez harakatlar, reaksiya mashqlari va portlovchi kuch mashqlari. Tezlik ayniqsa yengil atletika va o'yin sport turlarida muhim.","Kuch va tezlik birgalikda 'tezlik-kuch' sifatlarini hosil qiladi (masalan, sakrash, uloqtirish). Bu sifatlarni rivojlantirishda mashq yuklamasi (og'irlik, takrorlar soni, dam olish) to'g'ri belgilanishi kerak. Haddan tashqari yuklama shikastlanishga olib keladi."]),("Chidamlilikni rivojlantirish usullari",["Chidamlilik — sportchining charchoqqa qarshilik ko'rsatish va uzoq vaqt davomida samarali ish bajarish qobiliyatidir. U umumiy chidamlilik (uzoq muddatli o'rtacha yuklama) va maxsus chidamlilik (muayyan sport turiga xos) ga bo'linadi.","Chidamlilikni rivojlantirish usullari: uzluksiz usul (uzoq masofaga bir tekis yugurish), interval usul (yuklama va dam olishni navbatlash), takroriy usul va musobaqa usuli. Bu usullar yurak-qon tomir va nafas tizimlarini mustahkamlaydi.","Chidamlilik mashqlari aerob (kislorod ishtirokida — uzoq yugurish, suzish, velosiped) va anaerob (kislorodsiz — qisqa, intensiv yuklama) bo'lishi mumkin. Ikkala tur ham muhim — ular organizmning turli tizimlarini rivojlantiradi."]),("Epchillik va egiluvchanlikni rivojlantirish",["Epchillik (koordinatsiya) — murakkab harakatlarni tez va aniq o'zlashtirish hamda o'zgaruvchan sharoitlarda harakatni qayta qurish qobiliyatidir. Epchillikni rivojlantirish mashqlari: akrobatika elementlari, koordinatsion mashqlar, sport o'yinlari va yangi harakatlarni o'rganish.","Egiluvchanlik — bo'g'imlardagi harakatlarni katta amplitudada bajarish qobiliyatidir. U mushaklar va paylarning cho'ziluvchanligiga bog'liq. Egiluvchanlikni rivojlantirish mashqlari: cho'zilish (stretching), tebranish mashqlari va maxsus gimnastik mashqlar.","Epchillik va egiluvchanlik ko'p sport turlarida muhim: ular harakatlarni chiroyli, aniq va xavfsiz bajarishni ta'minlaydi. Yetarli egiluvchanlik shikastlanishlarning oldini oladi. Bu sifatlar ayniqsa gimnastika, akrobatika va kurashda hal qiluvchi ahamiyatga ega."])],})

TOPICS.append({"num":9,"title":"Sportchini texnik tayyorlashning mazmuni va bosqichlari","reja":["Texnik tayyorlashning mohiyati va ahamiyati.","Sport texnikasini o'rgatish bosqichlari.","Texnik xatolar va ularni tuzatish.","Texnik mahoratni takomillashtirish."],"sections":[("Texnik tayyorlashning mohiyati va ahamiyati",["Texnik tayyorlash — sport turiga xos harakatlarni to'g'ri, tejamli va samarali bajarishni o'rgatishga qaratilgan jarayondir. Sport texnikasi — bu sport harakatini bajarishning eng oqilona usuli bo'lib, u sportchiga maksimal natijaga erishish imkonini beradi.","Texnik tayyorlashning ahamiyati katta: hatto jismonan kuchli sportchi ham noto'g'ri texnika bilan yaxshi natija ko'rsata olmaydi. To'g'ri texnika kuchni tejaydi, harakatni aniqlashtirib, samaradorlikni oshiradi va shikastlanish xavfini kamaytiradi.","Texnika sport turiga bog'liq: har bir sport turida o'ziga xos texnik elementlar bor (yugurish texnikasi, sakrash texnikasi, to'p tepish texnikasi, kurash usullari). Bu elementlarni mukammal egallash — sport mahoratining asosidir."]),("Sport texnikasini o'rgatish bosqichlari",["Sport texnikasini o'rgatish uch asosiy bosqichdan iborat: 1) dastlabki o'rganish (harakat bilan tanishish, umumiy tasavvur hosil qilish), 2) chuqurlashtirilgan o'rganish (harakatni aniqlashtirish va detallarini o'zlashtirish), 3) mustahkamlash va takomillashtirish (avtomatizm darajasiga yetkazish).","Dastlabki bosqichda murabbiy harakatni ko'rsatadi, tushuntiradi va sportchi uni taqlid qiladi. Bu bosqichda ko'p xatolar bo'ladi — bu tabiiy. Asosiy maqsad — harakatning umumiy tuzilmasini o'zlashtirishdir, detallar keyinroq aniqlanadi.","Keyingi bosqichlarda harakat takror-takror bajariladi, xatolar tuzatiladi va harakat asta-sekin avtomatlashadi. Mukammal egallangan texnika sportchiga turli sharoitlarda (charchaganda, raqib bosimida) ham to'g'ri harakat qilish imkonini beradi."]),("Texnik xatolar va ularni tuzatish",["Texnik xatolar — harakatni noto'g'ri bajarish bo'lib, ular natijani pasaytiradi va shikastlanishga olib kelishi mumkin. Xatolar turli sabablarga ko'ra paydo bo'ladi: noto'g'ri tushunish, jismoniy tayyorgarlik yetishmasligi, charchash yoki qo'rquv.","Xatolarni tuzatish uchun avval ularning sababini aniqlash kerak. Murabbiy harakatni kuzatadi, video yozuvni tahlil qiladi va xatoning manbasini topadi. Keyin maxsus mashqlar va ko'rsatmalar orqali xato bartaraf etiladi.","Xatolarni tuzatishda muhim qoidalar: xatolarni erta aniqlash (ular odatga aylanmasdan), asosiy xatolardan boshlash (mayda xatolar keyin), bir vaqtda bitta xatoga e'tibor qaratish va sabr-toqat bilan ishlash. Xatoni tuzatish uni o'rganishdan qiyinroq bo'lishi mumkin."]),("Texnik mahoratni takomillashtirish",["Texnik mahoratni takomillashtirish — bu uzluksiz jarayon bo'lib, hatto yuqori malakali sportchilar ham doimo o'z texnikasini yaxshilab boradilar. Takomillashtirish harakatni turli sharoitlarda mustahkamlash va variativ qilishni o'z ichiga oladi.","Takomillashtirish usullari: harakatni turli tezlik va kuch bilan bajarish, murakkab sharoitlarda mashq qilish (charchash holatida, raqib bilan), video tahlil, biomexanik tahlil va eng yaxshi sportchilar texnikasini o'rganish. Zamonaviy texnologiyalar bu jarayonni osonlashtiradi.","Yuqori darajadagi texnik mahorat — bu harakatni mukammal, tejamli, aniq va turli sharoitlarda barqaror bajarish qobiliyatidir. Bunday mahorat ko'p yillik mehnat va minglab marta takrorlash natijasida shakllanadi. Texnik mahorat — chempionning asosiy belgisidir."])],})

TOPICS.append({"num":10,"title":"Sportchini taktik tayyorlashning mazmuni va mashqlari","reja":["Taktik tayyorlashning mohiyati va turlari.","Taktik fikrlash va qaror qabul qilish.","Taktik mashqlar va ularni bajarish.","Individual va jamoaviy taktika."],"sections":[("Taktik tayyorlashning mohiyati va turlari",["Taktik tayyorlash — sportchini musobaqada o'z imkoniyatlaridan oqilona foydalanib, raqibni yengish usullariga o'rgatishga qaratilgan jarayondir. Taktika — bu g'alaba qozonish uchun kuch va vositalarni to'g'ri tashkil etish san'atidir.","Taktika ikki turga bo'linadi: hujum taktikasi (raqibga bosim o'tkazish, hujum qilish) va himoya taktikasi (raqib hujumini to'xtatish, himoyalanish). Sport turiga qarab ularning nisbati o'zgaradi. Mukammal sportchi ikkala taktikani ham egallaydi.","Taktik tayyorlashning mazmuni: taktik bilimlarni o'zlashtirish (nazariy), taktik ko'nikmalarni rivojlantirish (amaliy), taktik fikrlashni shakllantirish va musobaqa tajribasini orttirish. Bularning hammasi birgalikda taktik mahoratni hosil qiladi."]),("Taktik fikrlash va qaror qabul qilish",["Taktik fikrlash — musobaqa davomida tez va to'g'ri qaror qabul qilish qobiliyatidir. Sportchi vaziyatni baholashi, raqib niyatini taxmin qilishi, o'z imkoniyatlarini hisobga olishi va eng oqilona harakatni tanlashi kerak — bularning hammasi soniyalar ichida.","Qaror qabul qilish jarayoni: vaziyatni idrok etish (nima sodir bo'lmoqda), tahlil qilish (variantlarni baholash), qaror qabul qilish (eng yaxshi variantni tanlash) va amalga oshirish (harakatni bajarish). Tajribali sportchi bu jarayonni juda tez bajaradi.","Taktik fikrlashni rivojlantirish uchun: turli musobaqa vaziyatlarini tahlil qilish, video o'rganish, taktik o'yinlar va vaziyatli mashqlar bajariladi. Tajriba ortgan sari sportchining taktik fikrlashi tezlashadi va aniqlashadi."]),("Taktik mashqlar va ularni bajarish",["Taktik mashqlar — taktik ko'nikmalarni rivojlantirishga qaratilgan maxsus mashqlardir. Ular musobaqa sharoitlarini imitatsiya qiladi va sportchini turli vaziyatlarga tayyorlaydi. Bu mashqlar nazariy bilimlarni amaliy ko'nikmaga aylantiradi.","Taktik mashqlar turlari: sxema bo'yicha mashqlar (oldindan belgilangan harakatlar), shartli mashqlar (ma'lum cheklovlar bilan), o'quv o'yinlari (real musobaqaga yaqin) va musobaqa mashqlari. Mashqlar oddiy dan murakkabga qarab boriladi.","Taktik mashqlarni bajarishda real musobaqa sharoitlarini yaratish muhim: raqib qarshiligi, vaqt bosimi, charchash holati. Bu sportchini haqiqiy musobaqaga tayyorlaydi. Mashqdan keyin tahlil o'tkazilib, xatolar muhokama qilinadi."]),("Individual va jamoaviy taktika",["Individual taktika — sportchining yakka tartibda raqibga qarshi qo'llaydigan taktik harakatlaridir. U yakka sport turlarida (kurash, boks, tennis) hal qiluvchi ahamiyatga ega. Sportchi raqibni o'rganib, o'ziga mos taktik reja tuzadi.","Jamoaviy taktika — jamoa a'zolarining birgalikdagi muvofiqlashtirilgan harakatlaridir. U jamoaviy sport turlarida (futbol, basketbol, voleybol) muhim. Jamoaviy taktika a'zolar o'rtasidagi o'zaro tushunish va hamkorlikni talab qiladi.","Jamoaviy taktikada har bir o'yinchining roli aniq belgilanadi va ular birgalikda umumiy maqsad yo'lida harakat qiladilar. Muvaffaqiyatli jamoaviy taktika individual mahorat va jamoaviy uyg'unlikning birikmasidir. Murabbiy jamoa taktikasini ishlab chiqadi va mashq qildiradi."])],})

TOPICS.append({"num":11,"title":"Sportchini ruhiy tayyorlashning mazmuni va usullari","reja":["Ruhiy (psixologik) tayyorlashning mohiyati.","Sportchining ruhiy sifatlari.","Musobaqa oldidan ruhiy tayyorgarlik.","Stress va his-hayajonni boshqarish usullari."],"sections":[("Ruhiy (psixologik) tayyorlashning mohiyati",["Ruhiy tayyorlash — sportchining psixologik sifatlarini rivojlantirish va musobaqaga ruhiy jihatdan tayyorlashga qaratilgan jarayondir. Zamonaviy sportda, ayniqsa yuqori darajada, ruhiy tayyorgarlik ko'pincha g'alaba va mag'lubiyat o'rtasidagi hal qiluvchi omil bo'ladi.","Ruhiy tayyorlashning ahamiyati: bir xil jismoniy va texnik darajadagi sportchilar o'rtasida aynan ruhiy barqarorlik g'olibni belgilaydi. Hatto eng kuchli sportchi ham ruhiy bosim ostida o'z imkoniyatlarini namoyon eta olmasligi mumkin.","Ruhiy tayyorlash umumiy (sportchining shaxsiyatini rivojlantirish) va maxsus (muayyan musobaqaga tayyorlash) ga bo'linadi. Sport psixologi va murabbiy birgalikda sportchining ruhiy tayyorgarligini ta'minlaydi."]),("Sportchining ruhiy sifatlari",["Sportchi uchun zarur bo'lgan ruhiy sifatlar: irodaviy sifatlar (qat'iyat, matonat, jasorat, o'zini tuta bilish), emotsional barqarorlik (his-hayajonni boshqarish), diqqatni jamlash qobiliyati, motivatsiya (g'alabaga intilish) va o'ziga ishonch.","Iroda — sportchining maqsadga erishish yo'lidagi qiyinchiliklarni yengish qobiliyatidir. U mashg'ulotlarda charchoqni yengish, og'riqqa chidash va qiyin damlarda taslim bo'lmaslikda namoyon bo'ladi. Iroda mashqlar va sinovlar orqali mustahkamlanadi.","Motivatsiya — sportchini faoliyatga undovchi ichki kuch. U ichki (sportning o'zidan zavq olish) va tashqi (mukofot, e'tirof) bo'lishi mumkin. Kuchli va barqaror motivatsiya sportchining uzoq muddatli muvaffaqiyati uchun zarur shartdir."]),("Musobaqa oldidan ruhiy tayyorgarlik",["Musobaqa oldidan sportchi turli ruhiy holatlarni boshdan kechirishi mumkin: 'musobaqa tayyorligi' (optimal holat), 'musobaqa isitmasi' (haddan tashqari hayajon) yoki 'musobaqa apatiyasi' (befarqlik, ruhiy tushkunlik). Optimal holatga erishish muhim.","Musobaqaga ruhiy tayyorgarlik usullari: musobaqa rejasini aniq tasavvur qilish (vizualizatsiya), ijobiy o'z-o'ziga ishontirish, nafas mashqlari orqali tinchlanish, qiziqtirib turuvchi marosimlar (ritual) va murabbiyning qo'llab-quvvatlashi. Bu usullar sportchini ishonchli holatga keltiradi.","Vizualizatsiya (xayolan tasavvur qilish) — kuchli usul: sportchi musobaqani, o'z harakatlarini va muvaffaqiyatli natijani xayolan tasavvur qiladi. Bu miyani musobaqaga tayyorlaydi, ishonchni oshiradi va harakatlarni mustahkamlaydi."]),("Stress va his-hayajonni boshqarish usullari",["Stress va his-hayajon sportda tabiiy holat, lekin ularni boshqarish kerak. Haddan tashqari hayajon harakatlarni buzadi, diqqatni chalg'itadi va xatolarga olib keladi. Sportchi o'z his-hayajonini nazorat qilishni o'rganishi shart.","His-hayajonni boshqarish usullari: nafas olishni nazorat qilish (chuqur va sekin nafas olish tinchlantiradi), mushaklarni bo'shashtirish (relaksatsiya), diqqatni jamlash texnikalari, ijobiy fikrlash va o'z-o'ziga buyruq berish. Bu usullar mashq qilinishi kerak.","Sport psixologi sportchiga maxsus texnikalarni o'rgatadi: autogen mashq (o'z-o'zini ishontirish orqali tinchlanish), meditatsiya, idiomotorli mashq (xayolan harakatni bajarish). Zamonaviy sportda psixologik tayyorgarlik alohida fan sifatida rivojlanmoqda va katta ahamiyat kasb etmoqda."])],})

TOPICS.append({"num":12,"title":"O'qitishning maqsad va vazifalari","reja":["O'qitish jarayoni tushunchasi va mohiyati.","Jismoniy tarbiyada o'qitishning maqsadi.","O'qitishning asosiy vazifalari.","O'qitish tamoyillari."],"sections":[("O'qitish jarayoni tushunchasi va mohiyati",["O'qitish — bu o'qituvchi (murabbiy) va o'quvchi (sportchi) o'rtasidagi maqsadli, tashkil etilgan va boshqariladigan o'zaro faoliyat bo'lib, uning natijasida o'quvchi bilim, ko'nikma va malakalarni egallaydi. Jismoniy tarbiyada o'qitish harakat ko'nikmalari va jismoniy sifatlarni shakllantirishga qaratilgan.","O'qitish jarayoni ikki tomonlama: o'qituvchi faoliyati (o'rgatish — bilim berish, ko'rsatish, tuzatish) va o'quvchi faoliyati (o'rganish — qabul qilish, takrorlash, mustahkamlash). Bu ikki faoliyat uyg'un bo'lganda o'qitish samarali bo'ladi.","Jismoniy tarbiyada o'qitishning o'ziga xosligi: u nafaqat nazariy bilim, balki amaliy harakat ko'nikmalarini ham shakllantiradi. O'quvchi harakatni ko'p marta takrorlab, uni mustahkamlaydi va avtomatlashtiradi. Bu jarayon jismoniy faollik bilan bog'liq."]),("Jismoniy tarbiyada o'qitishning maqsadi",["Jismoniy tarbiyada o'qitishning bosh maqsadi — o'quvchining har tomonlama jismoniy rivojlanishini ta'minlash, sog'lig'ini mustahkamlash va sog'lom turmush tarzini shakllantirishdir. Bu maqsad shaxsning uyg'un rivojlanishiga xizmat qiladi.","Maqsad konkret natijalarda ifodalanadi: harakat ko'nikmalarini egallash, jismoniy sifatlarni rivojlantirish, sport-texnik mahoratni oshirish, gigiyenik bilimlarni o'zlashtirish va mustaqil shug'ullanish ko'nikmasini shakllantirish. Bu natijalar o'lchanadigan bo'lishi kerak.","O'qitish maqsadi o'quvchining yoshi, jismoniy tayyorgarligi va sport turiga qarab aniqlashtiriladi. Maktab jismoniy tarbiyasida umumiy rivojlanish, sport maktabida esa sport mahoratini oshirish ustun turadi. Maqsad aniq, real va erishish mumkin bo'lishi kerak."]),("O'qitishning asosiy vazifalari",["O'qitishning vazifalari uch guruhga bo'linadi: ta'limiy vazifalar (bilim va ko'nikma berish), tarbiyaviy vazifalar (axloqiy va irodaviy sifatlarni shakllantirish) va sog'lomlashtirish vazifalari (sog'liqni mustahkamlash, jismoniy rivojlanishni ta'minlash).","Ta'limiy vazifalar: harakat texnikasini o'rgatish, sport turi qoidalarini tushuntirish, nazariy bilim berish va mustaqil shug'ullanish ko'nikmasini shakllantirish. Bu vazifalar o'quvchining sport savodxonligini oshiradi.","Tarbiyaviy vazifalar: irodaviy sifatlar (qat'iyat, matonat), axloqiy fazilatlar (halollik, hurmat, jamoaviylik), intizom va mas'uliyatni shakllantirish. Sport orqali shaxs tarbiyalanadi — bu jismoniy tarbiyaning muhim ijtimoiy funksiyasidir."]),("O'qitish tamoyillari",["O'qitish tamoyillari — o'qitish jarayonini samarali tashkil etish uchun rioya qilinishi kerak bo'lgan asosiy qoidalardir. Asosiy tamoyillar: onglilik va faollik, ko'rgazmalilik, izchillik va tizimlilik, mustahkamlik, individuallik va mavjudlik (o'quvchi imkoniyatiga moslik).","Onglilik va faollik tamoyili: o'quvchi o'rganayotgan harakatning maqsadini va mohiyatini tushunishi, faol ishtirok etishi kerak. Ko'rgazmalilik tamoyili: harakatni ko'rsatish, tushuntirish va namoyish etish o'rganishni osonlashtiradi.","Izchillik tamoyili: o'qitish oddiydan murakkabga, ma'lumdan noma'lumga qarab boriladi. Mustahkamlik tamoyili: egallangan bilim va ko'nikmalar takrorlash orqali mustahkamlanadi. Bu tamoyillarga rioya qilish o'qitish samaradorligini ta'minlaydi."])],})

TOPICS.append({"num":13,"title":"O'qitish maqsadi va vositalari, usullari, yangi pedagogik texnologiyalar","reja":["O'qitish vositalari va ularning turlari.","O'qitish usullari va metodlari.","Yangi pedagogik texnologiyalar.","Zamonaviy texnologiyalarni jismoniy tarbiyada qo'llash."],"sections":[("O'qitish vositalari va ularning turlari",["O'qitish vositalari — o'qitish maqsadiga erishish uchun foydalaniladigan barcha materiallar va imkoniyatlardir. Jismoniy tarbiyada asosiy vosita — jismoniy mashqlar, shuningdek sport jihozlari, ko'rgazmali qurollar va texnik vositalar.","Jismoniy mashqlar — o'qitishning asosiy vositasi: ular umumrivojlantiruvchi (barcha mushaklarni rivojlantiradi), maxsus (muayyan sport turiga xos) va musobaqa mashqlariga bo'linadi. Mashqlar to'g'ri tanlanishi va dozalanishi kerak.","Yordamchi vositalar: sport jihozlari (to'plar, gantellar, trenajyorlar), ko'rgazmali qurollar (plakatlar, sxemalar, video), texnik vositalar (kompyuter, proektor) va tabiat omillari (quyosh, havo, suv — chiniqish uchun). Ular o'qitishni samarali qiladi."]),("O'qitish usullari va metodlari",["O'qitish usuli — o'qituvchi va o'quvchining maqsadga erishishga qaratilgan o'zaro faoliyat usulidir. Jismoniy tarbiyada asosiy usullar guruhlari: so'z usullari, ko'rgazmali usullar va amaliy usullar.","So'z usullari: tushuntirish, suhbat, ko'rsatma berish, baholash. Ko'rgazmali usullar: harakatni namoyish etish, video ko'rsatish, plakat va sxemalardan foydalanish. Amaliy usullar: mashq qilish, o'yin usuli, musobaqa usuli — bular jismoniy tarbiyada asosiy o'rin tutadi.","Mashq qilish usuli — harakatni rejali takrorlash. U yaxlit (harakatni to'liq bajarish) va qismlarga bo'lib (murakkab harakatni qismlarga ajratib o'rgatish) usullariga bo'linadi. O'yin va musobaqa usullari o'quvchilarni qiziqtiradi va faollashtiradi."]),("Yangi pedagogik texnologiyalar",["Yangi pedagogik texnologiyalar — o'qitish jarayonini samarali, qiziqarli va natijaga yo'naltirilgan qilishga qaratilgan zamonaviy usul va vositalardir. Ular an'anaviy o'qitishni boyitadi va o'quvchilar faolligini oshiradi.","Zamonaviy texnologiyalar: interaktiv o'qitish (o'quvchilar faol ishtiroki), muammoli o'qitish (muammoni hal qilish orqali o'rganish), differensial o'qitish (har bir o'quvchining imkoniyatiga moslash), loyiha usuli va o'yin texnologiyalari. Ular o'quvchilarni motivatsiyalaydi.","Hamkorlikda o'qitish texnologiyasi: o'quvchilar kichik guruhlarda birgalikda ishlaydilar, bir-biriga yordam beradilar. Bu jamoaviylikni rivojlantiradi va o'qitish samaradorligini oshiradi. Sport o'yinlari va estafetalar bu texnologiyaga mos keladi."]),("Zamonaviy texnologiyalarni jismoniy tarbiyada qo'llash",["Axborot-kommunikatsiya texnologiyalari (AKT) jismoniy tarbiyaga ham kirib keldi: video tahlil (harakatni yozib, tahlil qilish), sport ilovalari, fitnes-trekerlar (yurak urishi, masofa, kaloriya), onlayn mashg'ulotlar va elektron jurnallar.","Video tahlil — kuchli vosita: o'quvchi harakati yozib olinadi, sekin tezlikda ko'riladi va xatolar aniqlanadi. O'quvchi o'z harakatini tashqaridan ko'rib, xatolarini tushunadi. Bu texnikani tezroq va aniqroq o'rganishga yordam beradi.","Zamonaviy qurilmalar: yurak urish monitorlari, qadam sanagichlar, GPS-trekerlar mashg'ulot yuklamasini nazorat qiladi. Bu ma'lumotlar mashg'ulotni individuallashtirishga va optimallashtirishga yordam beradi. Texnologiyalar jismoniy tarbiyani zamonaviy va samarali qiladi."])],})

TOPICS.append({"num":14,"title":"O'qitish usullari va baholash turlari","reja":["O'qitish usullarini tanlash mezonlari.","Bilim va ko'nikmalarni baholash mohiyati.","Baholash turlari va shakllari.","Jismoniy tarbiyada baholash mezonlari."],"sections":[("O'qitish usullarini tanlash mezonlari",["O'qitish usulini to'g'ri tanlash o'qitish samaradorligini belgilaydi. Usul tanlashda quyidagilar hisobga olinadi: o'qitish maqsadi va vazifalari, o'quvchilarning yoshi va tayyorgarligi, o'rganilayotgan material xususiyatlari, mavjud sharoit va vaqt.","Turli vazifalar uchun turli usullar mos keladi: yangi harakatni o'rgatishda ko'rgazmali usul (namoyish), texnikani mustahkamlashda mashq usuli, qiziqishni oshirishda o'yin usuli, natijani tekshirishda musobaqa usuli. Usullar kombinatsiyada qo'llaniladi.","Samarali o'qitish uchun usullar moslashuvchan tanlanadi: bir usul barcha holatlar uchun mos kelmaydi. Tajribali o'qituvchi vaziyatga qarab usullarni o'zgartiradi va kombinatsiyalaydi. Bu o'qitishni jonli va samarali qiladi."]),("Bilim va ko'nikmalarni baholash mohiyati",["Baholash — o'quvchining bilim, ko'nikma va malakalari darajasini aniqlash va o'lchash jarayonidir. U o'qitish natijasini ko'rsatadi va o'qitish jarayonini boshqarishga yordam beradi. Baholash adolatli, xolis va asosli bo'lishi kerak.","Baholashning funksiyalari: nazorat (bilim darajasini aniqlash), o'qitish (xatolarni ko'rsatish orqali o'rgatish), tarbiyaviy (mas'uliyat va intizomni shakllantirish), rag'batlantirish (motivatsiya berish) va tashxis (o'qitish samaradorligini aniqlash). Baholash ko'p qirrali jarayon.","Baholash obyektiv (aniq o'lchanadigan — vaqt, masofa, takrorlar soni) va subyektiv (o'qituvchi fikriga asoslangan — texnika sifati) bo'lishi mumkin. Jismoniy tarbiyada ikkala tur ham qo'llaniladi. Adolatli baholash uchun aniq mezonlar zarur."]),("Baholash turlari va shakllari",["Baholash turlari: dastlabki baholash (o'qitish boshida — boshlang'ich darajani aniqlash), joriy baholash (o'qitish davomida — har bir darsda), oraliq baholash (mavzu yoki bo'lim oxirida) va yakuniy baholash (o'quv yili yoki kurs oxirida).","Dastlabki baholash o'quvchining boshlang'ich darajasini aniqlaydi va o'qitishni rejalashtirish uchun asos bo'ladi. Joriy baholash o'qitish jarayonini nazorat qiladi va kerak bo'lganda tuzatishlar kiritish imkonini beradi. Yakuniy baholash umumiy natijani ko'rsatadi.","Baholash shakllari: testlar (jismoniy tayyorgarlik normativlari), nazorat mashqlari, musobaqalar, og'zaki so'rov (nazariy bilim) va kuzatish. Jismoniy tarbiyada amaliy baholash (normativ topshirish) asosiy o'rin tutadi."]),("Jismoniy tarbiyada baholash mezonlari",["Jismoniy tarbiyada baholash bir necha mezon asosida amalga oshiriladi: jismoniy tayyorgarlik darajasi (normativlar), harakat texnikasi sifati, nazariy bilimlar, mashg'ulotlardagi faollik va shaxsiy yutuqlar dinamikasi (o'sish).",", Muhim tamoyil — har bir o'quvchining individual rivojlanishini hisobga olish: faqat mutlaq natija emas, balki o'quvchining shaxsiy o'sishi ham baholanadi. Zaif o'quvchining sezilarli yaxshilanishi yuqori baho olishga loyiq bo'lishi mumkin.","Adolatli baholash uchun mezonlar oldindan aniq belgilanishi va o'quvchilarga tushuntirilishi kerak. O'quvchi nima uchun va qanday baholanishini bilishi muhim. Bu baholashni shaffof qiladi va o'quvchilarni rag'batlantiradi. Baholash o'quvchini qo'rqitmasdan, rivojlanishga undashi kerak."])],})

TOPICS.append({"num":15,"title":"O'qitishning ilmiy asoslari va natijalari","reja":["O'qitishning ilmiy asoslari.","Jismoniy tarbiya nazariyasi va metodikasi.","O'qitish natijalarini tahlil qilish.","O'qitish sifatini oshirish yo'llari."],"sections":[("O'qitishning ilmiy asoslari",["O'qitish ilmiy asoslarga tayanadi — bu uning samaradorligini ta'minlaydi. Jismoniy tarbiyada o'qitish bir necha fan yutuqlariga asoslanadi: pedagogika (o'qitish qonuniyatlari), psixologiya (o'rganish jarayoni), fiziologiya (organizm funksiyalari), biomexanika (harakat tahlili) va tibbiyot.","Ilmiy yondashuv o'qitishni intuitiv emas, balki asoslangan qilib boradi: mashq yuklamasi fiziologik qonuniyatlarga muvofiq belgilanadi, harakat texnikasi biomexanik tahlil asosida o'rgatiladi, o'quvchilar bilan ishlash psixologik xususiyatlarni hisobga oladi.","Zamonaviy sport fani doimo rivojlanmoqda: yangi metodikalar, texnologiyalar va tadqiqotlar paydo bo'lmoqda. O'qituvchi va murabbiy bu yangiliklardan xabardor bo'lib, o'z ishida qo'llashi kerak. Ilmiy asoslangan o'qitish — yuqori natijalarning kafolatidir."]),("Jismoniy tarbiya nazariyasi va metodikasi",["Jismoniy tarbiya nazariyasi va metodikasi — jismoniy tarbiya jarayonining qonuniyatlari, tamoyillari, vositalari va usullarini o'rganadigan fan. U jismoniy tarbiya bo'yicha mutaxassislar uchun nazariy va amaliy asos beradi.","Nazariya jismoniy tarbiyaning umumiy qonuniyatlarini o'rganadi: jismoniy sifatlar qanday rivojlanadi, harakat ko'nikmalari qanday shakllanadi, mashg'ulot qanday tashkil etiladi. Metodika esa bu qonuniyatlarni amaliyotda qo'llash usullarini ishlab chiqadi.","Bu fan o'qituvchiga muhim savollarga javob beradi: nimani o'rgatish (mazmun), qanday o'rgatish (usullar), qaysi vositalar bilan, qanday ketma-ketlikda va qanday baholash. Nazariya va metodikani bilish professional o'qituvchining asosiy talabidir."]),("O'qitish natijalarini tahlil qilish",["O'qitish natijalarini tahlil qilish — o'qitish maqsadlariga qay darajada erishilganini aniqlash jarayonidir. Tahlil o'qitishning kuchli va zaif tomonlarini ko'rsatadi va kelgusi ishni rejalashtirishga yordam beradi.","Natijalarni tahlil qilish usullari: baholash ko'rsatkichlarini taqqoslash (boshlang'ich va yakuniy holat), statistik tahlil, o'quvchilar yutuqlari dinamikasini kuzatish va maqsadga erishish darajasini aniqlash. Tahlil obyektiv ma'lumotlarga asoslanadi.","Tahlil natijalari asosida xulosalar chiqariladi: qaysi usullar samarali bo'ldi, qaysi o'quvchilar yordamga muhtoj, o'qitishda qanday o'zgartirishlar kerak. Bu xulosalar o'qitish sifatini uzluksiz yaxshilash uchun asos bo'ladi."]),("O'qitish sifatini oshirish yo'llari",["O'qitish sifatini oshirish — uzluksiz jarayon bo'lib, u bir necha yo'nalishda olib boriladi: o'qituvchining kasbiy mahoratini oshirish, zamonaviy usul va texnologiyalarni joriy etish, moddiy-texnik bazani yaxshilash va individual yondashuvni kuchaytirish.","O'qituvchining doimiy rivojlanishi muhim: malaka oshirish kurslari, yangi metodikalarni o'rganish, tajriba almashish, ilmiy adabiyotlarni o'qish va o'z ishini tahlil qilish. Professional o'qituvchi hech qachon o'rganishni to'xtatmaydi.","Individual yondashuv sifatni oshirishning muhim yo'li: har bir o'quvchining qobiliyati, ehtiyoji va imkoniyatini hisobga olish. Differensial o'qitish, qo'shimcha mashg'ulotlar va shaxsiy maslahatlar o'quvchilarning to'liq salohiyatini ochishga yordam beradi. Sifatli o'qitish — har bir o'quvchining muvaffaqiyatidir."])],})

